import{_ as t,o as i,c as a,ag as n}from"./chunks/framework.BKDXG6j6.js";const m=JSON.parse('{"title":"Activity and Fragment","description":"","frontmatter":{},"headers":[],"relativePath":"android-core/activity-fragment.md","filePath":"android-core/activity-fragment.md","lastUpdated":null}'),r={name:"android-core/activity-fragment.md"};function o(s,e,c,l,d,g){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="activity-and-fragment" tabindex="-1">Activity and Fragment <a class="header-anchor" href="#activity-and-fragment" aria-label="Permalink to &quot;Activity and Fragment&quot;">​</a></h1><p>Activities and Fragments are the primary UI building blocks in older standard Android development (before Jetpack Compose). They manage user interactions, lifecycles, and window composition.</p><h2 id="activity" tabindex="-1">Activity <a class="header-anchor" href="#activity" aria-label="Permalink to &quot;Activity&quot;">​</a></h2><p>An <code>Activity</code> represents a single screen with a user interface. It serves as an entry point for interacting with the user.</p><ul><li><strong>Responsibilities</strong>: <ul><li>Hosting UI components (via <code>setContentView</code>).</li><li>Handling Window-level events.</li><li>Interacting with the system back stack and saving instance state.</li></ul></li><li><strong>When to use</strong>: Generally, an app should have one main Activity (Single-Activity Architecture) or a few core Activities that host various Fragments.</li></ul><h2 id="fragment" tabindex="-1">Fragment <a class="header-anchor" href="#fragment" aria-label="Permalink to &quot;Fragment&quot;">​</a></h2><p>A <code>Fragment</code> represents a reusable portion of your app&#39;s UI. A Fragment must always be hosted in an Activity.</p><ul><li><strong>Responsibilities</strong>: <ul><li>Modularizing UI logic (e.g., a list pane and detail pane).</li><li>Can be added, removed, or replaced dynamically at runtime using <code>FragmentManager</code>.</li><li>Has its own distinct lifecycle that is inextricably tied to the host Activity&#39;s lifecycle.</li></ul></li><li><strong>Data Passing</strong>: Pass data between Fragments using <code>setFragmentResult</code>, a shared <code>ViewModel</code> (scoped to Activity or Navigation Graph), or Jetpack Navigation safe args.</li></ul><h2 id="single-activity-vs-multi-activity-architecture" tabindex="-1">Single Activity vs. Multi-Activity Architecture <a class="header-anchor" href="#single-activity-vs-multi-activity-architecture" aria-label="Permalink to &quot;Single Activity vs. Multi-Activity Architecture&quot;">​</a></h2><p><strong>Single-Activity Architecture:</strong> Provides better control over navigation, transitions, and state sharing. Uses one standard Activity (e.g., <code>MainActivity</code>) handling the Jetpack Navigation component, swapping out <code>Fragments</code> (or <code>Composables</code>) as users navigate. This is the modern standard for Android development.</p><p><strong>Multi-Activity Architecture:</strong> Older apps often map each logical screen to a distinct <code>Activity</code>. This can make passing large datasets, seamless transitions, and deep-linking complicated.</p><h2 id="interview-questions" tabindex="-1">Interview Questions <a class="header-anchor" href="#interview-questions" aria-label="Permalink to &quot;Interview Questions&quot;">​</a></h2><p><strong>Q: What is the main difference between adding and replacing a Fragment?</strong><em>Answer:</em> Adding a fragment puts it on top of existing ones (so the old one is still beneath it, consuming memory but visible if the new one is transparent). Replacing removes the existing fragments in that container before adding the new one. <code>replace</code> is generally better for flat navigation to free memory and prevent click-through issues.</p><p><strong>Q: When an Activity is destroyed on rotation, what happens to its Fragments?</strong><em>Answer:</em> The FragmentManager automatically saves the state of attached fragments and re-creates them when the Activity is re-created upon rotation. You must not instantiate a new Fragment inside <code>onCreate</code> of the Activity unless <code>savedInstanceState == null</code>, otherwise you&#39;ll get overlapping fragments.</p>',14)])])}const p=t(r,[["render",o]]);export{m as __pageData,p as default};
